features.snippet:
typedef struct { logic [1:0] a; logic [2:0] b; } mem_t;
 mem_t rf [0:7];
 logic [1:0] read_data_a;
 assign read_data_a = rf[addr].a;

logic [1:0] data_out_a;
wire [2:0] addr;
assign data_out_a = rf[addr].a;

wire wen;
wire [2:0] write_addr;
struct { logic [1:0] a; logic [2:0] b; } data_in;
always @(posedge clock) if (wen) rf[write_addr] <= data_in;
